  <!--<th>Descripción</th>-->\\r\\n                            <!--<th>Porcentaje</th>-->\\r\\n                            <!--<th></th>-->\\r\\n                            <!--</tr>-->\\r\\n                            <!--</thead>-->\\r\\n                            <!--<tbody>-->\\r\\n                            <!--<tr v-for=\\\"(row, index) in form.charges\\\">-->\\r\\n                            <!--<td>-->\\r\\n                            <!--<el-select v-model=\\\"row.charge_type_id\\\" @change=\\\"changeChargeType(index)\\\">-->\\r\\n                            <!--<el-option v-for=\\\"option in charge_types\\\" :key=\\\"option.id\\\" :value=\\\"option.id\\\" :label=\\\"option.description\\\"></el-option>-->\\r\\n                            <!--</el-select>-->\\r\\n                            <!--</td>-->\\r\\n                            <!--<td>-->\\r\\n                            <!--<el-input v-model=\\\"row.description\\\"> <i slot=\\\"prefix\\\" class=\\\"el-icon-edit-outline\\\"></i></el-input>-->\\r\\n                            <!--</td>-->\\r\\n                            <!--<td>-->\\r\\n                            <!--<el-input v-model=\\\"row.percentage\\\"> <i slot=\\\"prefix\\\" class=\\\"el-icon-edit-outline\\\"></i></el-input>-->\\r\\n                            <!--</td>-->\\r\\n                            <!--<td>-->\\r\\n                            <!--<button type=\\\"button\\\" class=\\\"btn btn-danger\\\" @click.prevent=\\\"clickRemoveCharge(index)\\\">x</button>-->\\r\\n                            <!--</td>-->\\r\\n                            <!--</tr>-->\\r\\n                            <!--</tbody>-->\\r\\n                            <!--</table>-->\\r\\n                            <!--</div>-->\\r\\n                            <!--<div class=\\\"col-md-12 px-0\\\" v-if=\\\"attribute_types.length > 0\\\">-->\\r\\n                            <!--<label class=\\\"control-label\\\">-->\\r\\n                            <!--Atributos-->\\r\\n                            <!--<a href=\\\"#\\\" @click.prevent=\\\"clickAddAttribute\\\">[+ Agregar]</a>-->\\r\\n                            <!--</label>-->\\r\\n                            <!--<table class=\\\"table\\\">-->\\r\\n                            <!--<thead>-->\\r\\n                            <!--<tr>-->\\r\\n                            <!--<th>Tipo</th>-->\\r\\n                            <!--<th>Descripción</th>-->\\r\\n                            <!--<th></th>-->\\r\\n                            <!--</tr>-->\\r\\n                            <!--</thead>-->\\r\\n                            <!--<tbody>-->\\r\\n                            <!--<tr v-for=\\\"(row, index) in form.attributes\\\">-->\\r\\n                            <!--<td>-->\\r\\n                            <!--<el-select v-model=\\\"row.attribute_type_id\\\" filterable @change=\\\"changeAttributeType(index)\\\">-->\\r\\n                            <!--<el-option v-for=\\\"option in attribute_types\\\" :key=\\\"option.id\\\" :value=\\\"option.id\\\" :label=\\\"option.description\\\"></el-option>-->\\r\\n                            <!--</el-select>-->\\r\\n                            <!--</td>-->\\r\\n                            <!--<td>-->\\r\\n                            <!--<el-input v-model=\\\"row.value\\\"> <i slot=\\\"prefix\\\" class=\\\"el-icon-edit-outline\\\"></i></el-input>-->\\r\\n                            <!--</td>-->\\r\\n                            <!--<td>-->\\r\\n                            <!--<button type=\\\"button\\\" class=\\\"btn btn-danger\\\" @click.prevent=\\\"clickRemoveAttribute(index)\\\">x</button>-->\\r\\n                            <!--</td>-->\\r\\n                            <!--</tr>-->\\r\\n                            <!--</tbody>-->\\r\\n                            <!--</table>-->\\r\\n                            <!--</div>-->\\r\\n                            <!--</div>-->\\r\\n                            <!--</section>-->\\r\\n                        </div>\\r\\n                    </template>\\r\\n                </div>\\r\\n            </div>\\r\\n            <div class=\\\"form-actions text-end pt-2 pb-2\\\">\\r\\n                <el-button @click.prevent=\\\"close()\\\">Cerrar</el-button>\\r\\n                <el-button\\r\\n                    class=\\\"add\\\"\\r\\n                    type=\\\"primary\\\"\\r\\n                    @click=\\\"clickAddItem()\\\"\\r\\n                    v-if=\\\"agregar_item\\\"\\r\\n                    >{{ titleAction }}</el-button\\r\\n                >\\r\\n            </div>\\r\\n        </form>\\r\\n        <item-form\\r\\n            :showDialog.sync=\\\"showDialogNewItem\\\"\\r\\n            :external=\\\"true\\\"\\r\\n        ></item-form>\\r\\n\\r\\n        <warehouses-detail\\r\\n            :showDialog.sync=\\\"showWarehousesDetail\\\"\\r\\n            :isUpdateWarehouseId=\\\"isUpdateWarehouseId\\\"\\r\\n            :warehouses=\\\"warehousesDetail\\\"\\r\\n        >\\r\\n        </warehouses-detail>\\r\\n\\r\\n        <lots-group\\r\\n            :quantity=\\\"form.quantity\\\"\\r\\n            :showDialog.sync=\\\"showDialogLots\\\"\\r\\n            :lots_group=\\\"form.lots_group\\\"\\r\\n            @addRowLotGroup=\\\"addRowLotGroup\\\"\\r\\n        >\\r\\n        </lots-group>\\r\\n\\r\\n        <select-lots-form\\r\\n            :showDialog.sync=\\\"showDialogSelectLots\\\"\\r\\n            :lots=\\\"lots\\\"\\r\\n            @addRowSelectLot=\\\"addRowSelectLot\\\"\\r\\n        >\\r\\n        </select-lots-form>\\r\\n    </el-dialog>\\r\\n</template>\\r\\n<style>\\r\\n.el-select-dropdown {\\r\\n    max-width: 80% !important;\\r\\n    margin-right: 5% !important;\\r\\n}\\r\\n</style>\\r\\n\\r\\n<script>\\r\\nimport ItemForm from \\\"../../items/form.vue\\\";\\r\\nimport LotsGroup from \\\"./lots_group.vue\\\";\\r\\n\\r\\nimport { calculateRowItem } from \\\"../../../helpers/functions\\\";\\r\\nimport WarehousesDetail from \\\"./select_warehouses.vue\\\";\\r\\nimport SelectLotsForm from \\\"./lots.vue\\\";\\r\\n\\r\\nexport default {\\r\\n    props: [\\r\\n        \\\"recordItem\\\",\\r\\n        \\\"showDialog\\\",\\r\\n        \\\"operationTypeId\\\",\\r\\n        \\\"percentage_igv\\\",\\r\\n        \\\"currencyTypeIdActive\\\",\\r\\n        \\\"exchangeRateSale\\\",\\r\\n        \\\"typeUser\\\",\\r\\n        \\\"isEditItemNote\\\",\\r\\n        \\\"configuration\\\",\\r\\n        \\\"idDetalle\\\",\\r\\n        \\\"restringir_stock\\\"\\r\\n    ],\\r\\n    components: { ItemForm, WarehousesDetail, LotsGroup, SelectLotsForm },\\r\\n    data() {\\r\\n        return {\\r\\n            loading_search: false,\\r\\n            titleAction: \\\"\\\",\\r\\n            is_client: false,\\r\\n            titleDialog: \\\"\\\",\\r\\n            resource: \\\"documents\\\",\\r\\n            showDialogNewItem: false,\\r\\n            has_list_prices: false,\\r\\n            errors: {},\\r\\n            form: {},\\r\\n            all_items: [],\\r\\n            items: [],\\r\\n            operation_types: [],\\r\\n            all_affectation_igv_types: [],\\r\\n            affectation_igv_types: [],\\r\\n            system_isc_types: [],\\r\\n            discount_types: [],\\r\\n            charge_types: [],\\r\\n            attribute_types: [],\\r\\n            use_price: 1,\\r\\n            change_affectation_igv_type_id: false,\\r\\n            activePanel: 0,\\r\\n            total_item: 0,\\r\\n            item_unit_types: [],\\r\\n            showWarehousesDetail: false,\\r\\n            warehousesDetail: [],\\r\\n            showListStock: false,\\r\\n            search_item_by_barcode: false,\\r\\n            isUpdateWarehouseId: null,\\r\\n            showDialogLots: false,\\r\\n            showDialogSelectLots: false,\\r\\n            lots: [],\\r\\n\\r\\n            item_select: null,\\r\\n            agregar_item: false,\\r\\n            form_control: {},\\r\\n            items_select: []\\r\\n        };\\r\\n    },\\r\\n    async created() {\\r\\n        this.initForm();\\r\\n        this.$http.get(`/${this.resource}/item/tables`).then(response => {\\r\\n            // this.items = response.data.items\\r\\n            this.all_items = response.data.items;\\r\\n            this.operation_types = response.data.operation_types;\\r\\n            this.affectation_igv_types = response.data.affectation_igv_types;\\r\\n            this.system_isc_types = response.data.system_isc_types;\\r\\n            this.discount_types = response.data.discount_types;\\r\\n            this.charge_types = response.data.charge_types;\\r\\n            this.attribute_types = response.data.attribute_types;\\r\\n            this.is_client = response.data.is_client;\\r\\n            // this.restringir_stock= response.data.restringir_stock;\\r\\n\\r\\n            this.filterItems();\\r\\n        });\\r\\n\\r\\n        this.$eventHub.$on(\\\"reloadDataItems\\\", item_id => {\\r\\n            this.reloadDataItems(item_id);\\r\\n        });\\r\\n\\r\\n        this.$eventHub.$on(\\\"selectWarehouseId\\\", warehouse_id => {\\r\\n            this.form.warehouse_id = warehouse_id;\\r\\n        });\\r\\n    },\\r\\n    methods: {\\r\\n        async searchRemoteItems(input) {\\r\\n\\r\\n            if (input.length > 2) {\\r\\n                this.loading_search = true;\\r\\n                let parameters = `input=${input}`;\\r\\n\\r\\n                await this.$http\\r\\n                    .get(`/${this.resource}/search-items/?${parameters}`)\\r\\n                    .then(response => {\\r\\n                        this.items_select = response.data[0];\\r\\n                        this.items = response.data;\\r\\n\\r\\n                        this.loading_search = false;\\r\\n\\r\\n                        this.enabledSearchItemsBarcode();\\r\\n\\r\\n                        if (this.items.length == 0) {\\r\\n                            this.filterItems();\\r\\n                        }\\r\\n                    });\\r\\n            } else {\\r\\n                await this.filterItems();\\r\\n            }\\r\\n        },\\r\\n        filterItems() {\\r\\n            this.items = this.all_items;\\r\\n        },\\r\\n        enabledSearchItemsBarcode() {\\r\\n            if (this.search_item_by_barcode) {\\r\\n                if (this.items.length == 1) {\\r\\n                    this.form.item_id = this.items[0].id;\\r\\n                    this.changeItem();\\r\\n                }\\r\\n            }\\r\\n        },\\r\\n        filterMethod(query) {\\r\\n            let item = _.find(this.items, { internal_id: query });\\r\\n\\r\\n            if (item) {\\r\\n                this.form.item_id = item.id;\\r\\n                this.changeItem();\\r\\n            }\\r\\n        },\\r\\n        clickWarehouseDetail() {\\r\\n            if (!this.form.item_id) {\\r\\n                return this.$toast.error(\\\"Seleccione un item\\\");\\r\\n            }\\r\\n\\r\\n            let item = _.find(this.items, { id: this.form.item_id });\\r\\n\\r\\n            this.warehousesDetail = item.warehouses;\\r\\n            this.showWarehousesDetail = true;\\r\\n        },\\r\\n        // filterItems(){\\r\\n        //     this.items = this.items.filter(item => item.warehouses.length >0)\\r\\n        // },\\r\\n\\r\\n        initForm() {\\r\\n            this.errors = {};\\r\\n            this.form = {\\r\\n                item_id: null,\\r\\n                item: {},\\r\\n                affectation_igv_type_id: null,\\r\\n                affectation_igv_type: {},\\r\\n                has_isc: false,\\r\\n                system_isc_type_id: null,\\r\\n                percentage_isc: 0,\\r\\n                suggested_price: 0,\\r\\n                quantity: 1,\\r\\n                unit_price_value: 0,\\r\\n                input_unit_price_value: 0,\\r\\n                unit_price: 0,\\r\\n                charges: [],\\r\\n                discounts: [],\\r\\n                attributes: [],\\r\\n                has_igv: null,\\r\\n                item_unit_types: [],\\r\\n                has_plastic_bag_taxes: false,\\r\\n                warehouse_id: null,\\r\\n                lots_group: [],\\r\\n                IdLoteSelected: null,\\r\\n                stock: \\\"Si\\\",\\r\\n                amount: 0.0,\\r\\n                stock_disp: null\\r\\n            };\\r\\n\\r\\n            this.activePanel = 0;\\r\\n            this.total_item = 0;\\r\\n            this.item_unit_type = {};\\r\\n            this.has_list_prices = false;\\r\\n        },\\r\\n        // initializeFields() {\\r\\n        //     this.form.affectation_igv_type_id = this.affectation_igv_types[0].id\\r\\n        // },\\r\\n        async create() {\\r\\n            this.titleDialog = this.recordItem\\r\\n                ? \\\" Modificar Producto o Servicio\\\"\\r\\n                : \\\" Agregar Producto o Servicio\\\";\\r\\n            this.titleAction = this.recordItem ? \\\" Modificar\\\" : \\\"Agregar\\\";\\r\\n            let operation_type = await _.find(this.operation_types, {\\r\\n                id: this.operationTypeId\\r\\n            });\\r\\n            //        this.affectation_igv_types = await _.filter(this.all_affectation_igv_types, {exportation: operation_type.exportation})\\r\\n\\r\\n            if (this.recordItem) {\\r\\n                this.form.item_id = await this.recordItem.item_id;\\r\\n                await this.searchRemoteItems(this.recordItem.item.description);\\r\\n                await this.changeItem();\\r\\n                this.form.quantity = this.recordItem.quantity;\\r\\n                this.form.unit_price_value = this.recordItem.unit_price;\\r\\n                this.form.has_plastic_bag_taxes =\\r\\n                    this.recordItem.total_plastic_bag_taxes > 0 ? true : false;\\r\\n                this.form.warehouse_id = this.recordItem.warehouse_id;\\r\\n                this.isUpdateWarehouseId = this.recordItem.warehouse_id;\\r\\n                this.form.stock = this.recordItem.item.is_stock;\\r\\n                this.item_select = this.recordItem;\\r\\n                if (this.isEditItemNote) {\\r\\n                    this.form.item.currency_type_id = this.currencyTypeIdActive;\\r\\n                    this.form.item.currency_type_symbol =\\r\\n                        this.currencyTypeIdActive == \\\"PEN\\\" ? \\\"S/\\\" : \\\"$\\\";\\r\\n                }\\r\\n\\r\\n                this.calculateQuantity();\\r\\n            } else {\\r\\n                this.isUpdateWarehouseId = null;\\r\\n            }\\r\\n        },\\r\\n        clickAddDiscount() {\\r\\n            this.form.discounts.push({\\r\\n                discount_type_id: null,\\r\\n                discount_type: null,\\r\\n                description: null,\\r\\n                percentage: 0,\\r\\n                factor: 0,\\r\\n                amount: 0,\\r\\n                base: 0,\\r\\n                is_amount: false\\r\\n            });\\r\\n        },\\r\\n        clickRemoveDiscount(index) {\\r\\n            this.form.discounts.splice(index, 1);\\r\\n        },\\r\\n        changeDiscountType(index) {\\r\\n            let discount_type_id = this.form.discounts[index].discount_type_id;\\r\\n            this.form.discounts[index].discount_type = _.find(\\r\\n                this.discount_types,\\r\\n                { id: discount_type_id }\\r\\n            );\\r\\n        },\\r\\n        clickAddCharge() {\\r\\n            this.form.charges.push({\\r\\n                charge_type_id: null,\\r\\n                charge_type: null,\\r\\n                description: null,\\r\\n                percentage: 0,\\r\\n                factor: 0,\\r\\n                amount: 0,\\r\\n                base: 0\\r\\n            });\\r\\n        },\\r\\n        clickRemoveCharge(index) {\\r\\n            this.form.charges.splice(index, 1);\\r\\n        },\\r\\n        changeChargeType(index) {\\r\\n            let charge_type_id = this.form.charges[index].charge_type_id;\\r\\n            this.form.charges[index].charge_type = _.find(this.charge_types, {\\r\\n                id: charge_type_id\\r\\n            });\\r\\n        },\\r\\n        clickAddAttribute() {\\r\\n            this.form.attributes.push({\\r\\n                attribute_type_id: null,\\r\\n                description: null,\\r\\n                value: null,\\r\\n                start_date: null,\\r\\n                end_date: null,\\r\\n                duration: null\\r\\n            });\\r\\n        },\\r\\n        clickRemoveAttribute(index) {\\r\\n            this.form.attributes.splice(index, 1);\\r\\n        },\\r\\n        changeAttributeType(index) {\\r\\n            let attribute_type_id = this.form.attributes[index]\\r\\n                .attribute_type_id;\\r\\n            let attribute_type = _.find(this.attribute_types, {\\r\\n                id: attribute_type_id\\r\\n            });\\r\\n            this.form.attributes[index].description =\\r\\n                attribute_type.description;\\r\\n            this.inputAttribute(index);\\r\\n        },\\r\\n        inputAttribute(index) {\\r\\n            let value = this.form.attributes[index].value;\\r\\n            let hotelAttributes = [\\\"4003\\\", \\\"4004\\\"];\\r\\n\\r\\n            this.form.attributes[index].start_date = hotelAttributes.includes(\\r\\n                this.form.attributes[index].attribute_type_id\\r\\n            )\\r\\n                ? value\\r\\n                : null;\\r\\n        },\\r\\n        close() {\\r\\n            this.initForm();\\r\\n            this.$emit(\\\"update:showDialog\\\", false);\\r\\n        },\\r\\n        async changeItem() {\\r\\n            /*  if(this.recordItem){\\r\\n                    this.form.item =this.items_select;\\r\\n                    this.form.item_unit_types =  this.form.item.item_unit_types\\r\\n               }else{\\r\\n                    this.form.item = _.find(this.items, {'id': this.form.it